// packages/database/src/db/schema/dataset-metadata.ts
// Drizzle table: datasetMetadata (generated by scripts/split-schema.ts)

import { createId } from '@paralleldrive/cuid2'
import { type AnyPgColumn, index, integer, pgTable, text, uniqueIndex } from './_shared'

import { Dataset } from './dataset'

/** Drizzle table for datasetMetadata */
export const DatasetMetadata = pgTable(
  'DatasetMetadata',
  {
    id: text()
      .$defaultFn(() => createId())
      .primaryKey()
      .notNull(),
    name: text().notNull(),
    type: text().default('string').notNull(),
    count: integer().default(0).notNull(),
    datasetId: text()
      .notNull()
      .references((): AnyPgColumn => Dataset.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
  },
  (table) => [
    index('DatasetMetadata_datasetId_idx').using('btree', table.datasetId.asc().nullsLast()),
    uniqueIndex('DatasetMetadata_datasetId_name_key').using(
      'btree',
      table.datasetId.asc().nullsLast(),
      table.name.asc().nullsLast()
    ),
    index('DatasetMetadata_type_idx').using('btree', table.type.asc().nullsLast()),
  ]
)
